import ScrollAnimation from 'react-animate-on-scroll';
import React from "react";

const AboutMe = () => {
    return(
        <ScrollAnimation
            duration={2}
            animateIn='fadeIn'
            animateOut='fadeOut'>
            <div className="ui center aligned segment">
                <h1 className="ui header" style={{fontWeight:"900"}}>About Me</h1>

            </div>
        </ScrollAnimation>

    )
};
export default AboutMe;
